function appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessRecordSignatureIssues(input: {
  readonly issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessLedgerIssue[];
  readonly path: string;
  readonly tenantId: TenantId | string;
  readonly record: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessRecord;
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
}): void {
  const policy = input.signaturePolicy;
  const topology = policy?.pruningTombstoneStoreHeadAuthorityTopology;
  if (policy === undefined || topology === undefined) {
    return;
  }
  const signature = input.record.signature;
  if (signature === undefined) {
    if (policy.required) {
      input.issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_missing",
        path: input.path,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness record requires a witness principal signature",
      });
    }
    return;
  }

  if (signature.principalId !== input.record.observerId) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_principal_mismatch",
      path: `${input.path}/principalId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature principal must match the observer id",
      expected: input.record.observerId,
      actual: signature.principalId,
    });
  }

  const expectedPayloadHash =
    computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessObservationSignaturePayloadHash(
      projectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadObservationFromRecord(
        input.record,
      ),
    );
  if (signature.payloadHash !== expectedPayloadHash) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_payload_mismatch",
      path: `${input.path}/payloadHash`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature payload hash does not match the observation body",
      expected: expectedPayloadHash,
      actual: signature.payloadHash,
    });
  }

  const principal = topology.principals.find(
    (candidate) =>
      candidate.witnessId === input.record.observerId &&
      candidate.status === "active" &&
      candidate.validFromPruningTombstoneSequence <=
        input.record.head.pruningTombstoneSequence,
  );
  if (principal === undefined) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_principal_not_authorized",
      path: `${input.path}/principalId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature principal is not active in the replayed pruning tombstone-store head authority topology",
      actual: signature.principalId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyStatus !== undefined &&
    principal.signatureKeyStatus !== "active"
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature key is not current in the replayed pruning tombstone-store head authority topology",
      expected: "active",
      actual: principal.signatureKeyStatus,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyId === undefined &&
    policy.required
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature has no active admitted key in the replayed pruning tombstone-store head authority topology",
      expected: "active admitted key",
      actual: signature.keyId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureKeyId !== undefined &&
    signature.keyId !== principal.signatureKeyId
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_key_mismatch",
      path: `${input.path}/keyId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature key does not match the admitted witness principal key",
      expected: principal.signatureKeyId,
      actual: signature.keyId,
    });
  }
  if (
    principal !== undefined &&
    principal.signatureAlgorithm !== undefined &&
    signature.algorithm !== principal.signatureAlgorithm
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_key_mismatch",
      path: `${input.path}/algorithm`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature algorithm does not match the admitted witness principal algorithm",
      expected: principal.signatureAlgorithm,
      actual: signature.algorithm,
    });
  }

  const verified = policy.verifier({
    tenantId: input.tenantId,
    principalId: signature.principalId,
    keyId: signature.keyId,
    algorithm: signature.algorithm,
    payloadHash: signature.payloadHash,
    signature: signature.signature,
    ...(signature.signedAt !== undefined ? { signedAt: signature.signedAt } : {}),
  });
  if (!verified) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_ledger_signature_invalid",
      path: `${input.path}/signature`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness record signature verifier rejected the signature",
    });
  }
}

