export function computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordHash(
  record: Omit<
    ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecord,
    "quorumCertificateRecordHash"
  >,
): string {
  return fingerprint64(canonicalStringify(record));
}

export function buildProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordWitnessEvidence(input: {
  readonly certificate: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificate;
  readonly witnessRecords: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessRecord[];
}): readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateWitnessEvidence[] {
  return sortedUniqueStrings(input.certificate.acceptedWitnessIds).map(
    (witnessId) => {
      const record = input.witnessRecords.find(
        (candidate) =>
          candidate.observerId === witnessId &&
          candidate.accepted &&
          candidate.decision.acceptedHeads.some((head) =>
            sameProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHead(
              head,
              input.certificate.head,
            ),
          ),
      );
      if (record === undefined) {
        throw new Error(
          `projection replay pruning tombstone-head pruning tombstone-store head quorum certificate missing accepted witness record for ${witnessId}`,
        );
      }
      return {
        witnessId,
        witnessSequence: record.witnessSequence,
        observationHash: record.observationHash,
        observedAt: record.observedAt,
        ...(record.signature !== undefined ? { signature: record.signature } : {}),
      };
    },
  );
}

export function replayProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecords(input: {
  readonly tenantId: TenantId | string;
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecord[];
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
  readonly compactionCheckpoint?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpoint;
  readonly compactionCheckpointAdmission?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpointAdmissionCertificate;
}): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordReplay {
  const tenant = String(input.tenantId);
  const records = [...input.records].sort(
    (a, b) => a.quorumCertificateSequence - b.quorumCertificateSequence,
  );
  const issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordIssue[] =
    [];
  let expectedSequence = 1;
  let expectedPreviousHash: string | undefined;
  let latestCertifiedRecord:
    | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecord
    | undefined;
  const recordCheckpoint =
    input.compactionCheckpoint?.quorumCertificateRecords;
  if (recordCheckpoint !== undefined) {
    const admissionValidation =
      validateProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpointAdmission(
        {
          tenantId: input.tenantId,
          checkpoint: input.compactionCheckpoint!,
          ...(input.compactionCheckpointAdmission !== undefined
            ? { admission: input.compactionCheckpointAdmission }
            : {}),
          ...(input.signaturePolicy !== undefined
            ? { signaturePolicy: input.signaturePolicy }
            : {}),
        },
      );
    if (!admissionValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_compaction_checkpoint_invalid",
        path: "/compactionCheckpointAdmission",
        message: admissionValidation.message,
      });
    }
    const checkpointValidation =
      verifyProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionCheckpointHash(
        input.compactionCheckpoint!,
      );
    if (!checkpointValidation.valid) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/checkpointHash",
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record compaction checkpoint hash does not match its body",
        expected: checkpointValidation.expectedHash,
        actual: input.compactionCheckpoint!.checkpointHash,
      });
    }
    if (
      String(input.compactionCheckpoint!.tenantId) !== tenant ||
      String(recordCheckpoint.tenantId) !== tenant
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/tenantId",
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record compaction checkpoint tenant mismatch",
        expected: tenant,
        actual: String(input.compactionCheckpoint!.tenantId),
      });
    }
    if (
      !Number.isInteger(
        recordCheckpoint.compactedThroughQuorumCertificateSequence,
      ) ||
      recordCheckpoint.compactedThroughQuorumCertificateSequence < 1 ||
      recordCheckpoint.compactedThroughQuorumCertificateRecordHash === ""
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_compaction_checkpoint_invalid",
        path: "/compactionCheckpoint/quorumCertificateRecords",
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record compaction checkpoint requires a positive compacted certificate-record sequence and record hash",
        actual: `${recordCheckpoint.compactedThroughQuorumCertificateSequence}:${recordCheckpoint.compactedThroughQuorumCertificateRecordHash}`,
      });
    }
    const latest = recordCheckpoint.latestCertifiedRecord;
    if (latest !== undefined) {
      const { quorumCertificateRecordHash, ...latestPayload } = latest;
      const expectedLatestHash =
        computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordHash(
          latestPayload,
        );
      if (
        quorumCertificateRecordHash !== expectedLatestHash ||
        !latest.certificate.certified ||
        latest.quorumCertificateSequence >
          recordCheckpoint.compactedThroughQuorumCertificateSequence
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_compaction_checkpoint_invalid",
          path: "/compactionCheckpoint/quorumCertificateRecords/latestCertifiedRecord",
          message:
            "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record compaction checkpoint latest certified record must be certified, within the compacted prefix, and hash-valid",
          expected: expectedLatestHash,
          actual: quorumCertificateRecordHash,
        });
      }
    }
    if (issues.length === 0) {
      expectedSequence =
        recordCheckpoint.compactedThroughQuorumCertificateSequence + 1;
      expectedPreviousHash =
        recordCheckpoint.compactedThroughQuorumCertificateRecordHash;
      latestCertifiedRecord = latest;
    }
  }

  for (const [index, record] of records.entries()) {
    const issueCountBefore = issues.length;
    if (String(record.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_tenant_mismatch",
        path: `/records/${index}/tenantId`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record tenant mismatch",
        expected: tenant,
        actual: String(record.tenantId),
      });
    }
    if (String(record.certificate.tenantId) !== tenant) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_tenant_mismatch",
        path: `/records/${index}/certificate/tenantId`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate tenant mismatch",
        expected: tenant,
        actual: String(record.certificate.tenantId),
      });
    }
    if (record.quorumCertificateSequence !== expectedSequence) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_sequence_gap",
        path: `/records/${index}/quorumCertificateSequence`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate records must be contiguous",
        expected: expectedSequence,
        actual: record.quorumCertificateSequence,
      });
    }
    if (
      (record.previousQuorumCertificateRecordHash ?? "") !==
      (expectedPreviousHash ?? "")
    ) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_previous_hash_mismatch",
        path: `/records/${index}/previousQuorumCertificateRecordHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record does not chain to the prior record",
        expected: expectedPreviousHash ?? "",
        actual: record.previousQuorumCertificateRecordHash ?? "",
      });
    }
    if (!record.certificate.certified || record.certificate.status !== "certified") {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_certificate_not_certified",
        path: `/records/${index}/certificate/status`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record can only admit a certified certificate as durable proof",
        expected: "certified",
        actual: record.certificate.status,
      });
    }

    const { quorumCertificateHash, ...certificatePayload } = record.certificate;
    const expectedCertificateHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateHash(
        certificatePayload,
      );
    if (quorumCertificateHash !== expectedCertificateHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_certificate_hash_mismatch",
        path: `/records/${index}/certificate/quorumCertificateHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record contains a certificate with a mismatched hash",
        expected: expectedCertificateHash,
        actual: quorumCertificateHash,
      });
    }

    const { quorumCertificateRecordHash, ...recordPayload } = record;
    const expectedRecordHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordHash(
        recordPayload,
      );
    if (quorumCertificateRecordHash !== expectedRecordHash) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_hash_mismatch",
        path: `/records/${index}/quorumCertificateRecordHash`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record hash does not match its body",
        expected: expectedRecordHash,
        actual: quorumCertificateRecordHash,
      });
    }

    const expectedWitnessIds = sortedUniqueStrings(
      record.certificate.acceptedWitnessIds,
    );
    const actualWitnessIds = sortedUniqueStrings(
      record.acceptedWitnessEvidence.map((evidence) => evidence.witnessId),
    );
    if (canonicalStringify(actualWitnessIds) !== canonicalStringify(expectedWitnessIds)) {
      issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_witness_evidence_mismatch",
        path: `/records/${index}/acceptedWitnessEvidence`,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record evidence must match accepted witness ids",
        expected: expectedWitnessIds.join(", "),
        actual: actualWitnessIds.join(", "),
      });
    }
    for (const [evidenceIndex, evidence] of record.acceptedWitnessEvidence.entries()) {
      if (
        !Number.isInteger(evidence.witnessSequence) ||
        evidence.witnessSequence < 1 ||
        evidence.observationHash === ""
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_witness_evidence_mismatch",
          path: `/records/${index}/acceptedWitnessEvidence/${evidenceIndex}`,
          message:
            "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate evidence requires a positive witness sequence and observation hash",
          actual: `${evidence.witnessSequence}:${evidence.observationHash}`,
        });
      }
    }

    const seal = record.authorityEpochSeal;
    if (seal !== undefined) {
      const { authorityHash, ...sealPayload } = seal;
      const expectedSealHash =
        computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessAuthorityTransitionHash(
          sealPayload,
        );
      if (
        seal.transitionKind !== "seal_authority_epoch" ||
        seal.sealedQuorumCertificateHash !==
          record.certificate.quorumCertificateHash ||
        seal.sealedAuthorityTopologyHash !==
          record.certificate.authorityTopologyHash ||
        seal.sealedThroughPruningTombstoneSequence !==
          record.certificate.head.pruningTombstoneSequence ||
        authorityHash !== expectedSealHash
      ) {
        issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_authority_seal_mismatch",
          path: `/records/${index}/authorityEpochSeal`,
          message:
            "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record seal must bind the certificate hash, authority topology, tombstone sequence, and transition hash",
          expected: `${record.certificate.quorumCertificateHash}:${
            record.certificate.authorityTopologyHash ?? ""
          }:${record.certificate.head.pruningTombstoneSequence}`,
          actual: `${seal.sealedQuorumCertificateHash ?? ""}:${
            seal.sealedAuthorityTopologyHash ?? ""
          }:${seal.sealedThroughPruningTombstoneSequence ?? ""}`,
        });
      }
    }
    appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordSignatureIssues(
      {
        issues,
        path: `/records/${index}`,
        tenantId: tenant,
        record,
        ...(input.signaturePolicy !== undefined
          ? { signaturePolicy: input.signaturePolicy }
          : {}),
      },
    );

    if (issues.length === issueCountBefore && record.certificate.certified) {
      latestCertifiedRecord = record;
    }
    expectedSequence = record.quorumCertificateSequence + 1;
    expectedPreviousHash = record.quorumCertificateRecordHash;
  }

  return {
    valid: issues.length === 0,
    tenantId: input.tenantId,
    records,
    ...(latestCertifiedRecord !== undefined ? { latestCertifiedRecord } : {}),
    issues,
  };
}

function appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordSignatureIssues(input: {
  readonly issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordIssue[];
  readonly path: string;
  readonly tenantId: TenantId | string;
  readonly record: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecord;
  readonly signaturePolicy?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessSignaturePolicy;
}): void {
  const policy = input.signaturePolicy;
  if (policy === undefined) {
    return;
  }
  const topology = policy.pruningTombstoneStoreHeadAuthorityTopology;
  for (const [index, evidence] of input.record.acceptedWitnessEvidence.entries()) {
    const path = `${input.path}/acceptedWitnessEvidence/${index}/signature`;
    const signature = evidence.signature;
    if (signature === undefined) {
      if (policy.required) {
        input.issues.push({
          code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_invalid",
          path,
          message:
            "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record evidence requires a witness signature",
        });
      }
      continue;
    }
    const expectedPayloadHash =
      computeProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessObservationSignaturePayloadHash(
        {
          tenantId: input.record.tenantId,
          observerId: evidence.witnessId,
          observedAt: evidence.observedAt,
          head: input.record.certificate.head,
        },
      );
    if (
      signature.principalId !== evidence.witnessId ||
      signature.payloadHash !== expectedPayloadHash
    ) {
      input.issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_invalid",
        path,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record evidence signature does not bind the witness and head payload",
        expected: `${evidence.witnessId}:${expectedPayloadHash}`,
        actual: `${signature.principalId}:${signature.payloadHash}`,
      });
    }
    const principal = topology?.principals.find(
      (candidate) =>
        candidate.witnessId === evidence.witnessId &&
        candidate.status === "active" &&
        candidate.validFromPruningTombstoneSequence <=
          input.record.certificate.head.pruningTombstoneSequence,
    );
    appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordSignatureKeyStatusIssues(
      {
        issues: input.issues,
        path,
        signature,
        ...(principal !== undefined ? { principal } : {}),
        required: policy.required,
      },
    );
    const verified = policy.verifier({
      tenantId: input.tenantId,
      principalId: signature.principalId,
      keyId: signature.keyId,
      algorithm: signature.algorithm,
      payloadHash: signature.payloadHash,
      signature: signature.signature,
      ...(signature.signedAt !== undefined
        ? { signedAt: signature.signedAt }
        : {}),
    });
    if (!verified) {
      input.issues.push({
        code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_invalid",
        path,
        message:
          "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record verifier rejected witness evidence signature",
      });
    }
  }
}

function appendProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordSignatureKeyStatusIssues(input: {
  readonly issues: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateRecordIssue[];
  readonly path: string;
  readonly signature: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessPrincipalSignature;
  readonly principal?: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessPrincipalState;
  readonly required: boolean;
}): void {
  const { principal } = input;
  if (principal === undefined) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_key_not_current",
      path: `${input.path}/principalId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record signature principal is not active in the replayed pruning tombstone-store head authority topology",
      actual: input.signature.principalId,
    });
    return;
  }
  if (
    principal.signatureKeyStatus !== undefined &&
    principal.signatureKeyStatus !== "active"
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record signature key is not current in the replayed pruning tombstone-store head authority topology",
      expected: "active",
      actual: principal.signatureKeyStatus,
    });
  }
  if (principal.signatureKeyId === undefined && input.required) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record signature has no active admitted key",
      expected: "active admitted key",
      actual: input.signature.keyId,
    });
  }
  if (
    principal.signatureKeyId !== undefined &&
    input.signature.keyId !== principal.signatureKeyId
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_key_not_current",
      path: `${input.path}/keyId`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record signature key does not match the current admitted principal key",
      expected: principal.signatureKeyId,
      actual: input.signature.keyId,
    });
  }
  if (
    principal.signatureAlgorithm !== undefined &&
    input.signature.algorithm !== principal.signatureAlgorithm
  ) {
    input.issues.push({
      code: "projection_replay_certificate_store_root_witness_settlement_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_replay_compaction_pruning_tombstone_store_head_witness_quorum_certificate_record_signature_key_not_current",
      path: `${input.path}/algorithm`,
      message:
        "projection replay pruning tombstone-head pruning tombstone-store head witness quorum certificate record signature algorithm does not match the current admitted principal algorithm",
      expected: principal.signatureAlgorithm,
      actual: input.signature.algorithm,
    });
  }
}

function sortedProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateWitnessEvidence(
  evidence: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateWitnessEvidence[],
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessQuorumCertificateWitnessEvidence[] {
  return [...evidence].sort((a, b) =>
    a.witnessId === b.witnessId
      ? a.witnessSequence - b.witnessSequence
      : a.witnessId.localeCompare(b.witnessId),
  );
}

function projectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadObservationFromRecord(
  record: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessRecord,
): ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadObservationInput {
  return {
    tenantId: record.tenantId,
    observerId: record.observerId,
    observedAt: record.observedAt,
	    head: record.head,
	    ...(record.consistencyProof !== undefined
	      ? { consistencyProof: record.consistencyProof }
	      : {}),
	    ...(record.signature !== undefined ? { signature: record.signature } : {}),
	  };
	}

function latestProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecordForLane(input: {
  readonly records: readonly ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecord[];
  readonly lane: ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningLane;
}):
  | ProjectionReplayCertificateStoreRootWitnessSettlementStoreHeadWitnessReplayCompactionPruningTombstoneStoreHeadWitnessReplayCompactionPruningTombstoneRecord
  | undefined {
  return [...input.records]
    .sort((a, b) => b.pruningTombstoneSequence - a.pruningTombstoneSequence)
    .find((record) =>
      record.prunedFrontiers.some((frontier) => frontier.lane === input.lane),
    );
}

